// 1️⃣ Obtenemos el array de intents del primer item recibido por este nodo.
// Si la propiedad "intents" no existe, devolvemos un array vacío para evitar errores.
const data = $input.first().json.intents || [];

// 2️⃣ Función que evalúa la prioridad numérica de un intent
// y devuelve un objeto con:
//   - emoji: Representación visual del nivel de prioridad
//   - texto: Nombre descriptivo del nivel de prioridad
function obtenerPrioridad(priority) {
  if (priority >= 1000000) return { emoji: '🔴', texto: 'Highest' }; // Prioridad máxima
  if (priority >= 750000)  return { emoji: '🟠', texto: 'High' };    // Prioridad alta
  if (priority >= 500000)  return { emoji: '🔵', texto: 'Normal' };  // Prioridad normal
  if (priority >= 250000)  return { emoji: '🟢', texto: 'Low' };     // Prioridad baja
  return { emoji: '🚫', texto: 'Ignore' };                           // Ignorado o desactivado
}

// 3️⃣ Recorremos cada intent y lo convertimos en un item compatible con n8n.
// Cada item incluirá:
//   - Nombre: El displayName del intent
//   - prioridad: Valor numérico de la prioridad del intent
//   - colorPrioridad: Emoji que representa la prioridad
//   - textoPrioridad: Descripción textual de la prioridad
const intents = data.map(intent => {

  // Extrae la información de prioridad del intent actual.
  // Si la propiedad "priority" no existe, usamos 0 como valor por defecto para evitar errores.
  const prioridadInfo = obtenerPrioridad(intent.priority || 0);

  // Construye el item final que n8n espera: { json: {...} }
  return {
    json: {
      Nombre: intent.displayName,
      prioridad: intent.priority,
      colorPrioridad: prioridadInfo.emoji,
      textoPrioridad: prioridadInfo.texto
    }
  };
});

// 4️⃣ Devolvemos el array de items para que n8n los procese.
// Cada item será una fila independiente si lo conectas, por ejemplo, a Google Sheets.
return intents;
